-- Find every ability in the DoN catalog whose name exists under MULTIPLE spell ids.
-- Name-based Book/CombatAbility checks are immune; id-based checks must accept all listed ids.
SELECT s2.name, GROUP_CONCAT(DISTINCT s2.id ORDER BY s2.id) AS all_ids
FROM spells_new s1
JOIN spells_new s2 ON s2.name = s1.name
WHERE s1.id IN (5038, 9703, 9709, 9730, 9742, 9749, 9809, 9812, 9824, 9863, 9872, 9929,
  10005, 10056, 10104, 10113, 10116, 10134, 10197, 10206, 10215, 10251, 10257, 10300,
  10339, 10349, 10364, 10476, 10482, 10555, 10583, 10602, 10617, 10656, 10659, 10662,
  10738, 10747, 10754, 10773, 10792, 10818, 10821, 10823, 10824, 10829, 10830, 10832,
  10833, 10839, 10848, 10849, 10851, 10852, 10854, 10855, 10857, 10858, 10860, 10861,
  10864, 10885, 10889, 10890, 10902, 10906, 10910, 10913, 10915, 10919, 10936, 10939,
  10940, 10948, 10949, 10965, 10973, 11835, 11840, 11854, 11866, 11923, 11928, 14093,
  14099, 14170, 14351, 14515, 14797, 15073, 15076, 15078, 15081, 15082, 15095, 15101,
  15102, 15104, 15113, 15115, 15117, 15119, 15120, 15122, 15134, 15135, 15137, 15140,
  15141, 15144, 15147, 15152, 15153, 15156, 15165, 15167, 15168, 15180, 15182, 15188,
  15191, 15192, 15212, 15213, 15216, 15222, 15225, 15230, 15231, 15233, 15235, 15238,
  15239, 15240, 15248, 15249, 15251, 15254, 15255, 15257, 15260, 15261, 15263, 15264,
  15280, 18904, 19537, 25036, 25252, 35234, 35299, 40294, 41232)
GROUP BY s2.name
HAVING COUNT(DISTINCT s2.id) > 1
ORDER BY s2.name;
